create database db_sibori;

CREATE TABLE menu (
    ->     id INT AUTO_INCREMENT PRIMARY KEY,
    ->     slug VARCHAR(50),
    ->     judul VARCHAR(100),
    ->     konten TEXT
    -> );

    CREATE TABLE admin (
    ->     id INT AUTO_INCREMENT PRIMARY KEY,
    ->     username VARCHAR(50) UNIQUE,
    ->     password VARCHAR(255)
    -> );

    CREATE TABLE penyusun (
    ->     id INT AUTO_INCREMENT PRIMARY KEY,
    ->     nama VARCHAR(100) NOT NULL,
    ->     foto VARCHAR(255),
    ->     bio TEXT,
    ->     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    -> );

    INSERT INTO admin (username, password)
    -> VALUES ('admin', MD5('admin123'));

INSERT INTO menu (slug, judul, konten) VALUES
('identitas', 'Identitas SI-BORI', 'SI-BORI (Smart Innovative Boardgame Geometri) hadir sebagai manifestasi media pembelajaran modern yang secara radikal mengubah wajah pembelajaran matematika dari sekadar hafalan rumus menjadi sebuah pengalaman eksploratif yang imersif. Melalui format permainan papan yang dinamis, media ini membedah kekakuan konsep geometri abstrak dan mentransformasikannya ke dalam realitas fisik yang dapat disentuh serta dimanipulasi oleh siswa. Kehadiran SI-BORI menciptakan jembatan kognitif yang kuat, di mana siswa diajak untuk menjadi arsitek logis yang harus menggunakan ketajaman numerasinya untuk menyelesaikan berbagai misi strategis terkait luas, volume, hingga sifat-sifat bangun ruang yang tersaji secara visual di atas papan permainan. Kekuatan utama yang membedakan SI-BORI dengan media lainnya adalah integrasi mendalam terhadap nilai etnomatematika Jawa Tengah. Dengan menghadirkan unsur arsitektur tradisional seperti rumah Joglo dan ornamen lokal ke dalam desain permainan, SI-BORI membuktikan bahwa matematika adalah bagian tak terpisahkan dari napas kebudayaan. Pendekatan ini tidak hanya memudahkan pemahaman konsep secara kontekstual, tetapi juga menumbuhkan rasa bangga dan kesadaran budaya pada diri siswa. Harmonisasi ini semakin diperkuat dengan sentuhan teknologi QR-Code yang menghubungkan interaksi fisik dengan platform digital informatif. Melalui sekali pindai, siswa akan diarahkan menuju portal web yang menyajikan informasi mendalam mengenai media pembelajaran ini, sekaligus membedah kekayaan kebudayaan Jawa Tengah dan keterkaitannya yang erat dengan prinsip-prinsip geometri, sehingga siswa mendapatkan wawasan sejarah yang lebih luas di tengah permainan. Lebih jauh lagi, SI-BORI berperan aktif sebagai katalisator dalam menstimulasi kemampuan spasial dan kecerdasan visual siswa. Aktivitas manipulasi bidak serta eksplorasi jaring-jaring bangun ruang mengasah ketajaman persepsi dalam memahami posisi, rotasi, dan proyeksi objek secara akurat. Di balik keseruan permainannya, SI-BORI secara sistematis membangun fondasi literasi dan numerasi yang kokoh melalui mekanisme gamifikasi yang menantang siswa untuk berpikir kritis dan solutif. Setiap langkah di atas papan permainan memerlukan analisis mendalam dan komunikasi matematis yang efektif, sehingga siswa tidak hanya cerdas secara individu, tetapi juga terlatih dalam berkolaborasi dan berkompetisi secara sehat. Sebagai solusi tuntas dalam mengatasi kecemasan matematika, SI-BORI memastikan bahwa setiap sesi belajar meninggalkan kesan emosional yang positif dan bermakna. Dengan mengubah ruang kelas menjadi arena petualangan intelektual, media ini berhasil membangun motivasi belajar yang tinggi dan resiliensi siswa dalam menghadapi tantangan logika yang kompleks. SI-BORI adalah wujud nyata dari pendidikan masa depan yang menghormati akar tradisi, merangkul kemajuan teknologi, dan memprioritaskan perkembangan kognitif serta karakter siswa secara holistik, menjadikan geometri sebagai ilmu yang hidup, menyenangkan, dan penuh makna bagi kehidupan mereka.'),

('logo', 'Filosofi Logo SI-BORI', 'Logo SI-BORI dirancang untuk melambangkan transformasi pembelajaran matematika yang kaku menjadi sebuah petualangan interaktif, di mana setiap elemen visualnya mencerminkan nilai edukasi, budaya, dan teknologi. 1) Wajah Penari Kretek Sebagai ikon khas Kudus yang sarat akan nilai historis, visualisasi wajah penari ini bukan sekadar elemen dekoratif, melainkan representasi mendalam bahwa pendidikan sejatinya harus bermuara pada pembentukan karakter siswa yang kokoh. Simbol ini mencerminkan ketekunan, kehalusan budi, dan kebanggaan yang berakar kuat pada identitas daerah, mengingatkan kita bahwa proses belajar mengajar tidak boleh melepaskan diri dari nilai-nilai kemanusiaan. Dalam perspektif SI-BORI, belajar bukan hanya tentang penguasaan deretan angka atau rumus yang kaku, melainkan sebuah perjalanan untuk membentuk pribadi yang santun, memiliki integritas, serta menaruh hormat setinggi-tingginya terhadap warisan leluhur sebagai kompas moral di tengah kemajuan zaman. 2) Lampu Berdampingan dengan simbol tradisi tersebut, kehadiran lampu yang menyala terang menjadi representasi visual dari lahirnya sebuah ide baru dan pencerahan intelektual. Cahaya ini melambangkan komitmen SI-BORI untuk mengubah paradigma belajar dari sekadar aktivitas menghafal pasif menjadi proses stimulasi mental yang aktif dan dinamis. Lampu yang berpijar mencerminkan momen "eureka" ketika seorang siswa berhasil memecahkan kebuntuan berpikir, sekaligus memicu kemampuan analisis kritis dalam membedah setiap tantangan. Secara filosofis, elemen ini menegaskan bahwa keberhasilan belajar diukur dari sejauh mana siswa mampu mengonstruksi pemikiran orisinal, menemukan solusi inovatif atas masalah yang kompleks, dan memiliki daya nalar yang tajam sebagai bekal kognitif mereka di masa depan. 3) Bentuk-Bentuk Geometri Kehadiran bentuk-bentuk geometris seperti kubus, kerucut, dan tabung dalam identitas visual ini bukanlah sekadar elemen estetika atau hiasan visual tanpa makna. Lebih dari itu, elemen-elemen tersebut merupakan representasi fundamental dari fokus utama SI-BORI dalam mengonstruksi pemahaman matematis siswa secara komprehensif. Kehadiran berbagai bangun ruang ini melambangkan komitmen untuk memperkuat kemampuan numerasi melalui interaksi langsung, di mana siswa diajak untuk membedah setiap sisi, sudut, dan volume sebagai bagian dari strategi permainan. 4) Warna Emas Penggunaan warna Emas dalam logo ini melambangkan pancaran kejayaan, standar kualitas tinggi, dan puncak intelektualitas yang ingin dicapai melalui proses pembelajaran. Secara psikologis, warna ini berfungsi sebagai pemantik semangat bagi siswa untuk berani memasang target tinggi dan mengejar mimpi mereka setinggi langit tanpa rasa takut. Emas merefleksikan sebuah ambisi untuk menjadi unggul dalam penguasaan literasi matematika dan numerasi, sekaligus menyimbolkan nilai berharga dari ilmu pengetahuan yang diperoleh. Dalam konteks SI-BORI, warna Emas adalah representasi dari kesuksesan kognitif dan prestasi gemilang yang lahir dari ketajaman berpikir serta dedikasi dalam belajar. 5) Warna Salem Warna Salem dihadirkan sebagai penyeimbang filosofis yang mewakili kelembutan hati, ketenangan, dan ketulusan kepribadian. Kehadiran warna ini membawa pesan bahwa setinggi apa pun pencapaian intelektual seseorang, mereka harus tetap berpijak di bumi dengan karakter yang mulia, penuh kasih, dan santun terhadap sesama. Salem mencerminkan sisi humanis dari pendidikan, di mana SI-BORI tidak hanya berfokus pada kecerdasan logika, tetapi juga pada kematangan emosional dan etika. Warna ini adalah simbol dari kerendahan hati dan empati, memastikan bahwa setiap ilmu yang diraih digunakan dengan cara yang bijak dan memberikan kedamaian bagi lingkungan sekitarnya.'),

('etnomatematika', 'Etnomatematika Jawa Tengah', 'Etnomatematika dalam SI-BORI hadir untuk membuktikan bahwa matematika bukanlah sekadar angka di atas kertas, melainkan napas budaya yang telah lama hidup dalam keseharian masyarakat Jawa Tengah. Melalui media ini, siswa diajak menelusuri jejak logika para leluhur yang tertuang dalam arsitektur megah, kelezatan kuliner, hingga artefak tradisional yang sarat akan nilai geometri. 1) Nasi Tumpeng (Kerucut) Bentuknya yang menjulang tinggi ke atas adalah contoh Kerucut. Bagian bawahnya bulat (lingkaran) dan ujungnya lancip. (Hampir di seluruh daerah Jawa Tengah). 2) Kue Wajik (Prisma Belah Ketupat) Kue manis ini dipotong miring supaya membentuk Prisma. Alasnya terlihat seperti jajar genjang atau belah ketupat. (Banyak ditemukan di Magelang dan Semarang). 3) Rumah Joglo (Limas Terpancung) Coba lihat atap paling atas rumah Joglo. Bentuknya seperti Limas yang dipotong bagian pucuknya. Jadi, bagian atasnya datar! (Rumah adat khas Jawa Tengah). 4) Kue Gabin Tapai (Balok) Dua biskuit kotak yang mengapit tapai ini membentuk Balok tipis. Ada sisi atas, bawah, dan samping yang semuanya berbentuk persegi panjang. (Camilan populer di Jawa Tengah). 5) Onde-onde (Bola) Jajanan bulat berbalur wijen ini adalah contoh Bola. Tidak punya sudut, hanya ada satu permukaan melengkung. (Sangat terkenal di daerah Mojokerto dan sekitarnya). 6) Kue Lapis Legit (Kubus atau Balok) Kue ini punya banyak lapisan warna. Kalau dipotong kotak sama panjang, jadilah Kubus yang cantik! (Sajian khas saat hari raya di Jawa Tengah). 7) Bedug Masjid (Tabung) Alat musik pukul di masjid ini bentuknya Tabung raksasa. Kulit sapinya berbentuk lingkaran, dan badannya melengkung panjang. (Contohnya ada di Masjid Agung Demak). 8) Gamelan Gender (Tabung & Prisma) Bilah logam yang dipukul itu berbentuk Prisma, sedangkan bambu panjang di bawahnya adalah Tabung untuk membuat suara jadi merdu. (Kesenian khas Jawa Tengah). 9) Lemper (Tabung) Nasi ketan isi ayam yang dibungkus daun pisang ini berbentuk Tabung kecil yang lucu. (Camilan wajib di daerah Solo dan Yogyakarta). 10) Lontong (Tabung) Mirip lemper tapi lebih panjang. Lontong adalah contoh Tabung yang tinggi. (Sering ditemukan sebagai teman makan sate di Jawa Tengah). 11) Caping Petani (Kerucut) Topi yang dipakai pak tani di sawah ini berbentuk Kerucut. Bagian dalamnya kosong supaya bisa dipakai di kepala. (Banyak dipakai petani di daerah Kudus dan sekitarnya). 12) Jadah (Balok) Ketan putih yang kenyal ini biasanya dipotong kotak-kotak berbentuk Balok yang rapi. (Sangat terkenal di daerah Selo, Boyolali). 13) Bakul Nasi / Tumbu (Limas Terpancung) Wadah nasi dari bambu ini unik. Bawahnya kotak (persegi), tapi atasnya melebar jadi lingkaran. Mirip Limas yang dipotong. (Alat dapur tradisional Jawa Tengah). 14) Kue Ku / Kue Thok (Setengah Bola) Kue merah yang kenyal ini bentuknya seperti Setengah Bola yang sedikit lonjong. (Sering ada di pasar tradisional Jawa Tengah). 15) Kentongan (Tabung Berongga) Terbuat dari batang bambu atau kayu yang dilubangi tengahnya. Bentuk dasarnya adalah Tabung. (Alat ronda di desa-desa Jawa Tengah). 16) Serabi Solo (Tabung Sangat Pendek) Bentuknya bulat dan tipis. Walaupun tipis, serabi tetap punya tinggi, jadi termasuk Tabung yang sangat pendek. (Makanan khas Solo). 17) Candi Borobudur (Limas Berundak) Kalau dilihat dari jauh, candi ini berbentuk Limas raksasa yang punya banyak tingkatan kotak. (Terletak di Magelang). 18) Stupa Candi (Campuran Setengah Bola & Kerucut) Stupa adalah gabungan dua bangun ruang. Bawahnya bulat seperti Setengah Bola, atasnya lancip seperti Kerucut. (Ada di Candi Borobudur). 19) Kue Putu (Tabung) Kue ini dimasak di dalam bambu kecil, jadi saat keluar bentuknya pasti Tabung mengikuti bambunya. (Banyak dijual keliling di Jawa Tengah). 20) Gapura Candi Bentar (Prisma Terbelah) Gapura pintu masuk ini seperti sebuah bangunan tinggi yang dibelah tengahnya. Setiap belahannya berbentuk Prisma. (Banyak di situs sejarah seperti di Demak atau Kudus).'),

('gladhen', 'Kartu Gladhen', 'To be continued..'),

('penyusun', 'Seputar Penyusun', '• Dr. Henry Suryo Bintoro, S. Pd., M. Pd. Dr. Henry Suryo Bintoro, S. Pd., M. Pd. lahir di • Galeh Febrian Agustino Galeh Febrian Agustino, lahir di Kudus 23 Februari 2005. Penulis merupakan seorang mahasiswa aktif di Program Studi Pendidikan Matematika, Fakultas Keguruan dan Ilmu Pendidikan, Universitas Muria Kudus. Adapun kegiatan kemahasiswaan yang diikuti antara Himpunan Mahasiswa Pendidikan Matematika (HIMATIKA). • Meutya Rahma Hakim Meutya Rahma Hakim, lahir di Kudus • Luqyana Rosyada • Muhammad Rifky Nur Rahman • Muhammad Fajar Maulana • Muhammad Azka Latif'),

('dokumentasi', 'Dokumentasi SI-BORI', 'Dokumentasi ini merangkum perjalanan kreatif lahirnya SI-BORI, sebuah media pembelajaran yang mengubah kerumitan geometri menjadi petualangan visual yang seru. Di sini, kami mencatat bagaimana matematika, budaya Jawa Tengah, dan teknologi bersatu untuk menciptakan pengalaman belajar yang nyata bagi siswa. Melalui catatan ini, kami ingin memperlihatkan bahwa belajar numerasi tidak harus kaku. Dengan SI-BORI, setiap anak diajak untuk berpikir kritis, mengasah logika ruang, dan tetap mencintai warisan leluhur. Inilah wujud nyata komitmen kami untuk masa depan pendidikan yang lebih inovatif dan berkarakter.');
